import * as Sentry from '@sentry/astro';

const environment = import.meta.env.PUBLIC_STAGE || 'development';
const isProduction = environment === 'production';
const isStaging = environment === 'staging';

const tracesSampleRate = isProduction ? 1.0 : isStaging ? 0.5 : 0.1;
const replaysSessionSampleRate = isProduction ? 0.1 : isStaging ? 0.05 : 0;
const replaysOnErrorSampleRate = isProduction ? 0.5 : isStaging ? 0.25 : 0;

const initSentry = () => {
  Sentry.init({
    dsn: import.meta.env.PUBLIC_SENTRY_DSN,
    environment,
    debug: false,
    tracesSampleRate,
    replaysSessionSampleRate,
    replaysOnErrorSampleRate,

    integrations: [
      Sentry.browserTracingIntegration(),
      Sentry.replayIntegration({
        maskAllText: true,
        blockAllMedia: true
      }),
      Sentry.captureConsoleIntegration({
        levels: ['warn', 'error']
      })
    ],

    ignoreErrors: [
      /^chrome-extension:\/\//,
      /^moz-extension:\/\//,
      'Network request failed',
      'Failed to fetch',
      'Load failed',
      'ResizeObserver loop limit exceeded',
      'ResizeObserver loop completed with undelivered notifications'
    ]
  });
};

if ('requestIdleCallback' in window) {
  requestIdleCallback(initSentry);
} else {
  setTimeout(initSentry, 2000);
}
